// // This is a 4-tap FIR filter with a 4-bit input and a 4-bit output. The filter coefficients are fixed as 4, 3, 2, and 1. The output is computed as the sum of the products of the input samples and the coefficients.
module fir_filter (  
    input [3:0] x0,  
    input [3:0] x1,  
    input [3:0] x2,  
    input [3:0] x3,  
    output reg [7:0] y  
);  
    always @(*) begin  
        y = (1 * x0) + (2 * x1) + (3 * x2) + (4 * x3);  
    end  
endmodule
